// helper to try decode and optionally reverse cells
function tryBrailleDecode(bits, tryReverse = false) {
  const brailleText = decodeBraille(bits, { tryReverse });
  return brailleText;
}

function detectShift(text) {
  const freq = {};
  for (const ch of text.toLowerCase()) {
    if (ch >= "a" && ch <= "z") freq[ch] = (freq[ch] || 0) + 1;
  }
  const pairs = Object.entries(freq);
  if (!pairs.length) return 0;
  pairs.sort((a,b) => b[1] - a[1]);
  const most = pairs[0][0];
  return (most.charCodeAt(0) - "e".charCodeAt(0) + 26) % 26;
}

function applyRotInPlace(s, shift) {
  return s.split("").map(ch => {
    if (ch >= "a" && ch <= "z") {
      return String.fromCharCode(((ch.charCodeAt(0)-97 - shift + 26) % 26) + 97);
    }
    if (ch >= "A" && ch <= "Z") {
      return String.fromCharCode(((ch.charCodeAt(0)-65 - shift + 26) % 26) + 65);
    }
    return ch;
  }).join("");
}

// Try normal bit-order first, then reversed cell-order if base64 fails
let brailleText = tryBrailleDecode(BIT_STRING, false);
let base64Str = brailleText.replace(/\s+/g, "");
let decoded = null;

try {
  decoded = decodeBase64(base64Str);
} catch (e) {
  // try reversed cell order
  brailleText = tryBrailleDecode(BIT_STRING, true);
  base64Str = brailleText.replace(/\s+/g, "");
  decoded = decodeBase64(base64Str);
}

